fn is_vowel(c: char) -> bool {
    match c {
        'a' | 'i' | 'u' | 'e' | 'o' => true,
        _ => false,
    }
}

pub fn main() {
    let S = rl().chars().vec();

    let mut ok = true;
    for i in 0..S.len() {
        if S[i] == 'n' || is_vowel(S[i]) || (i + 1 < S.len() && is_vowel(S[i + 1])) {
            continue;
        }

        ok = false;
        break;
    }

    println!("{}", if ok { "YES" } else { "NO" });
    return;
}
